# WRONG: accumulates all tokens first — user waits the same as non-streaming
def bad_stream_handler(user_message):
    chunks = []
    with client.messages.stream(...) as stream:
        for chunk in stream.text_stream:
            chunks.append(chunk)  # user is still waiting during this entire loop
    for chunk in chunks:
        yield chunk  # too late — full response is already generated

# CORRECT: yield inside the streaming context
def good_stream_handler(user_message):
    with client.messages.stream(
        model="claude-opus-4-5",
        max_tokens=1024,
        messages=[{"role": "user", "content": user_message}],
    ) as stream:
        for chunk in stream.text_stream:
            yield chunk  # each token is forwarded as soon as it arrives

# WRONG — nginx default (60s timeout kills 2-minute streams silently)
location /chat/ {
    proxy_pass http://backend;
}

# CORRECT — extend timeouts and disable buffering
location /chat/ {
    proxy_pass http://backend;
    proxy_read_timeout 300s;    # 5 minutes — adjust to your max generation time
    proxy_send_timeout 300s;
    proxy_buffering off;         # CRITICAL: disables nginx response buffering
    proxy_cache off;
    add_header X-Accel-Buffering no;
}
